def build_default_pcblib_library_data_segments() -> tuple[str, ...]:
    """Return the ordered default Library/Data segments for PcbLibBuilder."""
    segments: list[str] = list(DEFAULT_PCBLIB_LIBRARY_DATA_TOP_LEVEL_SEGMENTS)
    for block in DEFAULT_PCBLIB_LIBRARY_DATA_RECORD_BLOCKS:
        segments.extend(block)
    return tuple(segments)
